const data = $json;
const companyData = $('Prepare Company Data').item.json;
const locations = data.locations || [];
const primary = locations.find(l => l.is_primary) || locations[0] || {};
const countryFromAmplemarket = primary.country || '';
return { json: { ...companyData, countryFromAmplemarket } };

const companyData = $('Prepare Company Data').item.json;
const companyName = companyData.companyName || '';
const domain = companyData.domain || '';
let content = '';
let contentSource = '';
try {
  const scrapeData = $('Jina Website Scrape').item.json;
  const webContent = (scrapeData.data || {}).content || '';
  if (typeof webContent === 'string' && webContent.trim().length > 50) {
    content = webContent;
    contentSource = 'website';
  }
} catch(e) {}
if (!content) {
  try {
    const searchData = $('Jina Web Search').item.json;
    const results = searchData.data || [];
    if (Array.isArray(results)) {
      content = results.slice(0, 5).map(r => (r.title || '') + '
' + (r.content || r.description || '')).join('

');
    } else if (typeof results === 'string') {
      content = results;
    }
    if (content.trim()) contentSource = 'search';
  } catch(e) {}
}
content = content.replace(/!\[.*?\]\(.*?\)/g, '').replace(/https?://[^\s)]+\.(png|jpg|jpeg|gif|svg|webp|ico)[^\s)]*/gi, '').replace(/cookie[s]?\s*(policy|notice|consent|banner|settings)[^
]*/gi, '').replace(/
{3,}/g, '

').trim();
const maxChars = contentSource === 'search' ? 2000 : 3000;
if (content.length > maxChars) content = content.substring(0, maxChars) + '... [truncated]';
const prompt = `You are an expert at identifying the headquarters country of companies.
Below is web content scraped from this company's online presence.

COMPANY: ${companyName}
DOMAIN: ${domain || 'Not provided'}

WEB CONTENT:
${content || 'No content available'}

Based ONLY on the web content above, identify the headquarters country.

LOOK FOR (in order of reliability):
1. Physical address or registered office mentioned on the page
2. Phone number with international country code
3. VAT number, company registration number, or tax ID format
4. Legal entity type (e.g., GmbH, Ltd, BV, NV, SRL, SA, AB, Pty, Inc, LLC)
5. Language and regional formatting clues (currency symbols, date formats)

RESPONSE (JSON only, no markdown):
{"country": "<full country name>", "evidence": "<quote the specific text from the content that confirmed this>"}

RULES:
- Base your answer ONLY on the provided web content — do NOT use your own knowledge
- Use full English country names (e.g., "United Kingdom", not "UK")
- The evidence field MUST quote actual text from the page, not your reasoning
- If the content doesn't contain clear country indicators: {"country": "Unknown", "evidence": "No country indicators found in content"}`;
return { json: { companyId: companyData.companyId, companyName, domain, contentSource, contentLength: content.length, prompt } };

const geminiText = ($json?.candidates?.[0]?.content?.parts?.[0]?.text || '').trim();
const companyData = $('Prepare Company Data').item.json;
const contentSource = $('Prepare Gemini Input').item.json.contentSource || '';
let geminiCountry = '';
let geminiEvidence = '';
try {
  const cleaned = geminiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  const country = parsed.country || '';
  geminiEvidence = parsed.evidence || '';
  if (country && country !== 'Unknown') geminiCountry = country;
} catch (e) {}
return { json: { companyId: companyData.companyId, companyName: companyData.companyName, domain: companyData.domain, geminiCountry, geminiEvidence, contentSource } };

const d = $input.item.json;
const country = d.countryFromTLD || d.countryFromName || d.countryFromAmplemarket || d.geminiCountry || '';
let enrichmentSource = '';
if (d.countryFromTLD) enrichmentSource = 'TLD';
else if (d.countryFromName) enrichmentSource = 'Company name';
else if (d.countryFromAmplemarket) enrichmentSource = 'Amplemarket';
else if (d.geminiCountry) enrichmentSource = 'Jina+Gemini';
return { json: { companyId: d.companyId, companyName: d.companyName, country, enrichmentSource, resolved: true } };

const items = $json.data || [];
const resolved = items.filter(i => i.resolved);
const unknown = items.filter(i => !i.resolved);
const hubspotBase = 'https://app.hubspot.com/contacts/142047914/company/';
const sourceCounts = {};
for (const c of resolved) sourceCounts[c.enrichmentSource] = (sourceCounts[c.enrichmentSource] || 0) + 1;
const sourceStats = Object.entries(sourceCounts).map(([source, count]) => `${source}: ${count}`).join(' \u00b7 ');
let msg = `\ud83c\udf0d *Country Enrichment v2.1 \u2014 Run Complete*\n`;
msg += `*${resolved.length} enriched \u00b7 ${unknown.length} unknown*\n`;
if (sourceStats) msg += `*Sources:* ${sourceStats}\n`;
msg += `\n`;
if (resolved.length > 0) { msg += `\u2705 *Enriched*\n`; for (const c of resolved) { const url = hubspotBase + c.companyId; msg += `\u2022 <${url}|${c.companyName}> \u2192 *${c.country}* (${c.enrichmentSource})\n`; } }
if (unknown.length > 0) { msg += `\n\ud83d\udea9 *Unknown (flagged)*\n`; for (const c of unknown) { const url = hubspotBase + c.companyId; msg += `\u2022 <${url}|${c.companyName}>\n`; } }
return { json: { message: msg } };
